import{_ as a,o as i,c as n,ao as s}from"./chunks/framework.CTzCsLWe.js";const k=JSON.parse('{"title":"LLM refinement (optional, gated)","description":"","frontmatter":{},"headers":[],"relativePath":"llm.md","filePath":"llm.md","lastUpdated":null}'),t={name:"llm.md"};function l(o,e,r,d,c,p){return i(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="LLM-refinement-optional,-gated" tabindex="-1">LLM refinement (optional, gated) <a class="header-anchor" href="#LLM-refinement-optional,-gated" aria-label="Permalink to &quot;LLM refinement (optional, gated) {#LLM-refinement-optional,-gated}&quot;">​</a></h1><p>Mjolnir&#39;s deterministic passes produce correct, reasonably idiomatic Julia on their own. An <strong>optional</strong> stage can ask an LLM to polish a unit further — but the result is <strong>refactor-only and gated</strong>: a candidate is accepted only if it is proven behaviorally equivalent to the deterministic baseline. Behavior never changes silently.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">backend </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ollama_backend</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(; model </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;qwen2.5-coder&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or claude_backend(...)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">polished </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gated_refine</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(backend, baseline_julia; probes </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> my_probes)</span></span></code></pre></div><p>If <code>gated_refine</code> cannot verify equivalence (via <a href="/Mjolnir.jl/dev/api#Mjolnir.verify_equivalent"><code>verify_equivalent</code></a>), it discards the candidate and returns the deterministic baseline unchanged.</p><h2 id="Backends" tabindex="-1">Backends <a class="header-anchor" href="#Backends" aria-label="Permalink to &quot;Backends {#Backends}&quot;">​</a></h2><p>All backends implement the <a href="/Mjolnir.jl/dev/api#Mjolnir.LLMBackend"><code>LLMBackend</code></a> interface:</p><ul><li><p><a href="/Mjolnir.jl/dev/api#Mjolnir.HTTPBackend"><code>HTTPBackend</code></a> — Anthropic Messages API (direct Claude) or any OpenAI-compatible endpoint, including a local <strong>Ollama</strong> server (<code>claude_backend</code>, <code>ollama_backend</code>).</p></li><li><p><a href="/Mjolnir.jl/dev/api#Mjolnir.SubprocessBackend"><code>SubprocessBackend</code></a> — a local CLI / <code>llama.cpp</code> process.</p></li><li><p><a href="/Mjolnir.jl/dev/api#Mjolnir.ManualBackend"><code>ManualBackend</code></a> — export prompt artifacts and ingest responses (e.g. the Copilot path).</p></li><li><p><a href="/Mjolnir.jl/dev/api#Mjolnir.FunctionBackend"><code>FunctionBackend</code></a> — wrap any <code>String -&gt; String</code> function (useful in tests).</p></li></ul><p>See the <a href="./api">API reference</a> for the full surface.</p>`,8)])])}const u=a(t,[["render",l]]);export{k as __pageData,u as default};
